const EMAILJS_SERVICE_ID = "service_pyv3sjb";
const EMAILJS_TEMPLATE_ID = "template_71pn7ds";
const EMAILJS_PUBLIC_KEY = "g8dFjauUvC5hvXA4L";

function sendRuralBloomEmail(formType, details) {
  const senderName = details.from_name || details.organization || "Rural Bloom visitor";
  const senderEmail = details.from_email || "ruralbloomhealth@gmail.com";
  const title = [
    `Rural Bloom ${formType}`,
    details.organization && `Organization: ${details.organization}`,
    details.preferred_dates && `Preferred dates: ${details.preferred_dates}`,
    details.message && `Message: ${details.message}`,
  ].filter(Boolean).join("\n\n");
  const message = title || `Rural Bloom ${formType}`;

  return emailjs.send(
    EMAILJS_SERVICE_ID,
    EMAILJS_TEMPLATE_ID,
    {
      title,
      name: senderName,
      email: senderEmail,
      message,
      to_email: "ruralbloomhealth@gmail.com",
      from_email: senderEmail,
      from_name: senderName,
      form_type: formType,
      organization: details.organization || "",
      preferred_dates: details.preferred_dates || "",
      reply_to: senderEmail,
      submitted_at: new Date().toLocaleString(),
    },
    EMAILJS_PUBLIC_KEY
  );
}

function getEmailJSError(error) {
  console.error("EmailJS send failed:", error);
  return error?.text || error?.message || "EmailJS rejected the request. Check your service/template settings.";
}

