function NavBar({ page, setPage }) {
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 8);
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);
  return (
    <header
      className={`rb-header sticky top-0 z-40 backdrop-blur border-b ${scrolled ? "scrolled" : ""}`}
      style={{ background: "rgba(251,243,239,0.9)", borderColor: COLORS.blush }}
    >
      <div className={`rb-container flex items-center justify-between transition-all ${scrolled ? "h-14" : "h-16"}`}>
        <Logo onClick={() => { setPage("home"); setOpen(false); }} />
        <nav className="hidden lg:flex items-center rb-main-nav text-sm font-semibold">
          {NAV_ITEMS.map((item) => (
            <button
              key={item.id}
              onClick={() => setPage(item.id)}
              className={`rb-nav-link rb-focus py-1 ${page === item.id ? "active" : ""}`}
              style={{ color: page === item.id ? COLORS.deep : COLORS.ink }}
            >
              {item.label}
            </button>
          ))}
        </nav>
        <button
          className="lg:hidden rb-focus"
          onClick={() => setOpen((o) => !o)}
          aria-label={open ? "Close menu" : "Open menu"}
        >
          {open ? <X size={22} color={COLORS.mauve} /> : <Menu size={22} color={COLORS.mauve} />}
        </button>
      </div>
      {open && (
        <div className="lg:hidden rb-container pb-4 flex flex-col gap-3 text-sm font-semibold">
          {NAV_ITEMS.map((item) => (
            <button
              key={item.id}
              onClick={() => { setPage(item.id); setOpen(false); }}
              className="text-left rb-focus py-1"
              style={{ color: page === item.id ? COLORS.deep : COLORS.ink }}
            >
              {item.label}
            </button>
          ))}
        </div>
      )}
    </header>
  );
}

