/* ---------------- APP ---------------- */

export default function RuralBloomSite() {
  const [page, setPage] = useState("home");
  const scrollPct = useScrollProgress();

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, [page]);

  const pages = {
    home: <Home setPage={setPage} />,
    pamphlet: <Pamphlet setPage={setPage} />,
    about: <About />,
    feedback: <Feedback />,
    resources: <Resources setPage={setPage} />,
    newsletter: <Newsletter />,
    events: <Events />,
    chat: <HealthAI />,
    testimonials: <Testimonials />,
  };

  return (
    <div className="rb-root min-h-screen">
      <style>{styleTag}</style>
      <div className="rb-progress-track">
        <div className="rb-progress-bar" style={{ width: `${scrollPct}%` }} />
      </div>
      <NavBar page={page} setPage={setPage} />
      <div key={page} className="rb-page-fade">
        {pages[page] || pages.home}
      </div>
      <Footer setPage={setPage} />
    </div>
  );
}
